app.post('/2fa/verify', async (req, res) => {
  try {
    const { userId, code } = req.body || {};
    if (!userId || !code) {
      return res.status(400).json({ error: 'userId and code are required' });
    }

    const locked = await redis.get(lockKey(userId));
    if (locked) {
      return res.status(403).json({ error: 'Too many attempts. Account temporarily locked.' });
    }

    const stored = await redis.get(codeKey(userId));
    if (!stored) {
      return res.status(400).json({ error: 'Code expired or not found' });
    }

    const attempts = await redis.incr(attemptsKey(userId));
    if (attempts === 1) {
      await redis.expire(attemptsKey(userId), CODE_TTL_SECONDS);
    }

    if (attempts > MAX_ATTEMPTS) {
      await redis.set(lockKey(userId), '1', 'EX', CODE_TTL_SECONDS);
      await redis.del(codeKey(userId));
      return res.status(403).json({ error: 'Too many attempts. Account temporarily locked.' });
    }

    const providedHash = hashCode(String(code));
    if (providedHash !== stored) {
      return res.status(401).json({ error: 'Invalid code' });
    }

    await redis.multi()
      .del(codeKey(userId))
      .del(attemptsKey(userId))
      .del(lockKey(userId))
      .exec();

    return res.json({ success: true, accessGranted: true });
  } catch (err) {
    return res.status(500).json({ error: 'Verification failed' });
  }
});

